from textwrap import dedent
import re

[prompt_result] = llm_query_batched([
    dedent("""
    Draft the entire contents of style.css for a browser-based boids simulation app.

    Requirements:
    - Dark background: #0b1020.
    - Prevent scrollbars and ensure no extra margins.
    - html, body: height: 100%; margin: 0; padding: 0; background: #0b1020; color: #ddd; overflow: hidden;
    - canvas: display: block; width: 100vw; height: 100vh; background: transparent; margin: 0; padding: 0;
    - Optional but allowed: a minimal reset (box-sizing), :root { color-scheme: dark; }, canvas { touch-action: none; }

    Constraints:
    - Keep it minimal and robust.
    - Return ONLY the raw CSS. No explanations, no comments, no code fences.
    """).strip()
])

css = prompt_result.strip()
css = re.sub(r"```[a-zA-Z]*|```", "", css).strip()

# If the LLM returned something unexpected or too sparse, provide a safe fallback.
if "html" not in css or "canvas" not in css:
    css = dedent("""
    :root {
      color-scheme: dark;
    }

    * {
      box-sizing: border-box;
    }

    html, body {
      height: 100%;
      margin: 0;
      padding: 0;
      background: #0b1020;
      color: #ddd;
      overflow: hidden;
    }

    canvas {
      display: block;
      width: 100vw;
      height: 100vh;
      background: transparent;
      margin: 0;
      padding: 0;
      touch-action: none;
      border: 0;
      outline: 0;
    }
    """).strip()

done(css)
```

